const response = $.steps.scrapeDocs.response || {};
const data = response.data || response;
const markdown = (data.markdown || data.content || data.text || '').slice(0, 20000);
return { markdown, url: $.input.apiDocsUrl, contentLength: markdown.length };

const d = $.steps.extractContent.output;
const apiName = $.input.apiName;
let prompt = 'You are an API documentation expert. Extract all API endpoints from the following documentation and classify them.

';
prompt += 'API: ' + apiName + '
';
prompt += 'DOCS URL: ' + d.url + '

';
prompt += 'DOCUMENTATION CONTENT:
' + d.markdown + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Extract every API endpoint found
';
prompt += '- Classify each: CRUD type (create/read/update/delete), resource type
';
prompt += '- Include method, path, parameters, request/response bodies
';
prompt += '- Group by resource/entity

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "apiName": "' + apiName + '",
';
prompt += '  "baseUrl": "detected base URL",
';
prompt += '  "endpoints": [{
';
prompt += '    "method": "GET|POST|PUT|DELETE|PATCH",
';
prompt += '    "path": "/endpoint/path",
';
prompt += '    "description": "what it does",
';
prompt += '    "category": "CRUD type",
';
prompt += '    "resource": "resource name",
';
prompt += '    "parameters": ["param1", "param2"],
';
prompt += '    "auth": "required|optional|none"
';
prompt += '  }],
';
prompt += '  "resources": ["resource1", "resource2"],
';
prompt += '  "totalEndpoints": 0,
';
prompt += '  "summary": "brief API summary"
';
prompt += '}';
return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { apiName: $.input.apiName, baseUrl: '', endpoints: [], resources: [], totalEndpoints: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const endpoints = ai.endpoints || [];
const header = ['Method', 'Path', 'Description', 'Category', 'Resource', 'Parameters', 'Auth'];
const rows = endpoints.map(e => [
  e.method || 'GET',
  e.path || '',
  e.description || '',
  e.category || '',
  e.resource || '',
  (e.parameters || []).join(', '),
  e.auth || 'required'
]);
return { values: [header].concat(rows), endpointCount: endpoints.length };

const ai = $.steps.parseAI.output;
const endpoints = ai.endpoints || [];
const resources = ai.resources || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'API Schema Extracted', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + (ai.apiName || 'API') + '* — ' + endpoints.length + ' endpoints found' } });

if (ai.baseUrl) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Base URL:* `' + ai.baseUrl + '`' } });
}

if (resources.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Resources:* ' + resources.join(', ') } });
}

endpoints.slice(0, 5).forEach(e => {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '`' + (e.method || 'GET') + ' ' + (e.path || '') + '` — ' + (e.description || '').slice(0, 80) } });
});

if (ai.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.summary.slice(0, 500) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Saved to Google Sheets | Powered by Firecrawl + Claude AI' }] });

const fallback = 'API Schema: ' + endpoints.length + ' endpoints extracted from ' + (ai.apiName || 'API');
return { blocks, fallback };
